use std::fs; use std::io; pub struct Buffer { pub content: String, } impl Buffer { pub fn new() -> Self { Self { content: String::new() } } pub fn insert(&mut self, pos: usize, text: &str) { self.content.insert_str(pos, text); } pub fn delete(&mut self, pos: usize, len: usize) { if pos < self.content.len() { self.content.replace_range(pos..(pos + len).min(self.content.len()), ""); } } pub fn get_line(&self, line_index: usize) -> Option<&str> { self.content.lines().nth(line_index) } pub fn load_from_file(&mut self, path: &str) -> io::Result<()> { self.content = fs::read_to_string(path)?; Ok(()) } pub fn save_to_file(&self, path: &str) -> io::Result<()> { fs::write(path, &self.content) } }
